import React, { useState, useEffect } from "react";
import axios from "axios";

const AdminDashboard = () => {
  const [title, setTitle] = useState("");
  const [image, setImage] = useState(null);
  const [categoryId, setCategoryId] = useState("");
  const [categories, setCategories] = useState([]);
  const [message, setMessage] = useState("");

  const [newCategory, setNewCategory] = useState("");
  const [categoryMessage, setCategoryMessage] = useState("");

  // ✅ Fetch categories from backend
  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/gallery/categories");
      setCategories(res.data);
    } catch (error) {
      console.error("Failed to fetch categories", error);
    }
  };

  // ✅ Handle file selection
  const handleFileChange = (e) => {
    setImage(e.target.files[0]);
  };

  // ✅ Upload image function
  const handleUpload = async () => {
    if (!title || !image || !categoryId) {
      setMessage("⚠️ Please fill in all fields and select a category.");
      return;
    }

    const formData = new FormData();
    formData.append("title", title);
    formData.append("image", image);
    formData.append("categoryId", categoryId);

    try {
      await axios.post("http://localhost:5000/api/gallery/upload", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setMessage("✅ Image uploaded successfully!");
      setTitle("");
      setImage(null);
      setCategoryId("");
    } catch (error) {
      setMessage("❌ Upload failed. Try again.");
    }
  };

  // ✅ Create new category
  const createCategory = async () => {
    if (!newCategory.trim()) return setCategoryMessage("Please enter a category name.");

    try {
      await axios.post("http://localhost:5000/api/categories", {
        name: newCategory.trim(),
      });
      setCategoryMessage("✅ Category created!");
      setNewCategory("");
      fetchCategories(); // Refresh categories list
    } catch (error) {
      setCategoryMessage("❌ Failed to create category.");
    }
  };

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-3xl font-bold mb-6">📸 Admin Dashboard</h1>

      {/* 🔹 Image Upload Section */}
      <div className="bg-white p-6 rounded-lg shadow-md mb-8">
        <h2 className="text-xl font-semibold mb-4">Upload New Image</h2>

        <input
          type="text"
          placeholder="Image Title"
          className="p-2 border rounded w-full mb-3"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <select
          className="p-2 border rounded w-full mb-3"
          value={categoryId}
          onChange={(e) => setCategoryId(e.target.value)}
        >
          <option value="">Select a category</option>
          {categories.map((cat) => (
            <option key={cat.id} value={cat.id}>
              {cat.name}
            </option>
          ))}
        </select>

        <input
          type="file"
          className="p-2 border rounded w-full mb-3"
          onChange={handleFileChange}
        />

        <button
          onClick={handleUpload}
          className="w-full bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition"
        >
          Upload Image
        </button>

        {message && <p className="mt-4 text-center text-sm font-medium">{message}</p>}
      </div>

      {/* 🔹 Create New Category Section */}
      <div className="bg-white p-6 rounded-lg shadow-md">
        <h2 className="text-xl font-semibold mb-4">Create New Category</h2>
        <input
          type="text"
          placeholder="Category Name (e.g., Weddings)"
          className="p-2 border rounded w-full mb-3"
          value={newCategory}
          onChange={(e) => setNewCategory(e.target.value)}
        />
        <button
          onClick={createCategory}
          className="w-full bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700 transition"
        >
          Add Category
        </button>
        {categoryMessage && (
          <p className="mt-4 text-center text-sm font-medium">{categoryMessage}</p>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
